import numpy as np
from typing import List, Tuple

def cosine_similarity(query: np.ndarray, docs: np.ndarray) -> np.ndarray:
    query_norm = query / (np.linalg.norm(query) + 1e-8)
    docs_norm = docs / (np.linalg.norm(docs, axis=1, keepdims=True) + 1e-8)
    return docs_norm @ query_norm  # (n,)

def retrieve(
    query_emb: np.ndarray,
    doc_embs: np.ndarray,
    doc_texts: List[str],
    k: int
) -> List[Tuple[str, float]]:
    scores = cosine_similarity(query_emb, doc_embs)
    top_k_idx = np.argsort(scores)[::-1][:k]
    return [(doc_texts[i], float(scores[i])) for i in top_k_idx]

def format_rag_prompt(
    query_text: str,
    retrieved_docs: List[Tuple[str, float]]
) -> str:
    lines = ["Context:"]
    for i, (doc, score) in enumerate(retrieved_docs, 1):
        lines.append(f"[{i}] {doc}")
    lines.append("")
    lines.append(f"Question: {query_text}")
    lines.append("Answer:")
    return "\n".join(lines)
